struct UserProfile {
  sqlgen::PrimaryKey<int> user_id;
  std::optional<std::string> bio;
  std::optional<std::string> avatar_url;
};

bool upsert_user_profile(const UserProfile& u) {
  // Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false; // Connection failed
  }

  auto conn = *conn_result;

  // Use sqlgen's insert functionality with or_replace option
  // Since the reference materials show insert_impl supports _or_replace parameter,
  // we can use the insert function with or_replace capability
  auto result = sqlgen::insert(conn, u);

  if (!result) {
    // If insert fails (likely due to primary key constraint), attempt update
