    auto update_stmt = sqlgen::update<UserProfile>(
        sqlgen::set(&UserProfile::bio, u.bio),
        sqlgen::set(&UserProfile::avatar_url, u.avatar_url)
    ) | sqlgen::where(&UserProfile::user_id == u.user_id);

    auto update_result = update_stmt(conn);
    return update_result ? true : false;
  }

  return result ? true : false;
}

