namespace analyze_social_network {

struct User {
    sqlgen::PrimaryKey<int> user_id;
    std::string username;
    std::string email;
    sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
    std::optional<std::string> city;
};

struct Friendship {
    int user_id1;
    int user_id2;
    sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> friendship_date;
};

struct FriendConnection {
    std::string user1_name;
    std::string user2_name;
};

struct MutualFriendsResult {
    std::string user1;
    std::string user2;
    int mutual_count;
};

struct FriendOfFriendResult {
    std::string user1;
    std::string user2;
    std::string mutual_friend;
};

struct UserStats {
