    std::string user2;
};

std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
    using namespace sqlgen::literals;

    // Create in-memory database connection
    auto conn_result = sqlgen::sqlite::connect(":memory:");
    if (!conn_result) {
        throw std::runtime_error("Failed to connect to database");
    }
    auto conn = *conn_result;

    // Create tables
    auto create_users = conn | sqlgen::create_table<User>;
    auto create_friendships = conn | sqlgen::create_table<Friendship>;

    // Insert data
    auto insert_users = conn | sqlgen::insert(users);
    auto insert_friendships = conn | sqlgen::insert(friendships);

    // Query 1: Mutual friends using SELF-JOIN
    auto mutual_query = sqlgen::select_from<User, "u1">("username"_c)
        | sqlgen::inner_join<Friendship, "f1">("user_id"_c == "user_id1"_c)
        | sqlgen::inner_join<Friendship, "f2">("user_id2"_c == "user_id1"_c)
        | sqlgen::inner_join<User, "u2">("user_id2"_c == "user_id"_c)
        | sqlgen::where("user_id"_c < "user_id"_c)
        | sqlgen::group_by("user_id"_c, "user_id"_c)
        | sqlgen::having(sqlgen::count() > 0);

    auto mutual_result = mutual_query(conn);

    // Query 2: Users with more than average friends using nested query
    auto avg_friends_query = sqlgen::select_from<User, "u">("user_id"_c, "username"_c)
        | sqlgen::left_join<Friendship, "f">("user_id"_c == "user_id1"_c)
        | sqlgen::group_by("user_id"_c, "username"_c)
        | sqlgen::having(sqlgen::count("user_id2"_c) > 
            sqlgen::select_from<User, "avg_u">(
                sqlgen::select(sqlgen::avg(sqlgen::count("user_id2"_c))).from("u")
            ).to<int>());

    auto avg_friends_result = avg_friends_query(conn);

    // Query 3: Friend-of-friend relationships
    auto friend_of_friend_query = sqlgen::select_from<User, "u1">("username"_c)
        | sqlgen::inner_join<Friendship, "f1">("user_id"_c == "user_id1"_c)
        | sqlgen::inner_join<Friendship, "f2">("user_id2"_c == "user_id1"_c)
        | sqlgen::inner_join<User, "u2">("user_id2"_c == "user_id"_c)
        | sqlgen::where("user_id"_c != "user_id"_c)
        | sqlgen::group_by("user_id"_c, "user_id"_c);

    auto friend_of_friend_result = friend_of_friend_query(conn);

    // Query 4: Count friends per user
    auto friend_count_query = sqlgen::select_from<User, "u">("user_id"_c, "username"_c)
        | sqlgen::left_join<Friendship, "f">("user_id"_c == "user_id1"_c)
        | sqlgen::group_by("user_id"_c, "username"_c)
        | sqlgen::order_by(sqlgen::count("user_id2"_c).desc());

    auto friend_count_result = friend_count_query(conn);

    // Query 5: Same city recommendations
    auto recommendation_query = sqlgen::select_from<User, "u1">("username"_c)
        | sqlgen::inner_join<User, "u2">("city"_c == "city"_c && "user_id"_c != "user_id"_c)
        | sqlgen::where(!sqlgen::exists(
            sqlgen::select_from<Friendship, "f">("user_id1"_c, "user_id2"_c)
            | sqlgen::where(("user_id1"_c == "user_id"_c) && ("user_id2"_c == "user_id"_c))
        ));

    auto recommendation_result = recommendation_query(conn);

    // Process results (simplified for demonstration)
    std::vector<FriendConnection> results;

    // Add mutual friends results
    for (auto& [user1, user2] : mutual_result) {
        results.emplace_back(FriendConnection{
            .user1_name = user1,
            .user2_name = user2
        });
    }

    // Add friend-of-friend results
    for (auto& [user1, user2] : friend_of_friend_result) {
        results.emplace_back(FriendConnection{
            .user1_name = user1,
            .user2_name = user2
        });
    }

    // Add recommendations
    for (auto& [user1, user2] : recommendation_result) {
        results.emplace_back(FriendConnection{
            .user1_name = user1,
            .user2_name = user2
        });
    }

    return results;
}

}  // namespace analyze_social_network
```

**Key Implementation Details:**

1. **Database Connection**: Uses `sqlgen::sqlite::connect(":memory:")` to create an in-memory SQLite database
2. **Table Creation**: Uses `sqlgen::create_table<T>` with the defined structs
3. **Data Insertion**: Uses `sqlgen::insert()` to populate tables with provided data
4. **SELF-JOIN Query**: Implements mutual friends detection using nested joins
5. **Nested Query**: Uses subquery to find users with above-average friend counts
6. **Friend-of-Friend**: Detects indirect connections through mutual friends
7. **Aggregation**: Uses `count()` and `avg()` for statistical analysis
8. **Recommendations**: Finds potential connections in the same city

The implementation follows sqlgen's fluent API pattern using the `operator|` for method chaining and leverages the library's type-safe query building capabilities.

