std::vector<MathAnalysis> analyze_mathematical_operations(const std::vector<Product>& products) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // 1. Connect to SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // 2. Create table (if not exists)
  auto create_result = (create_table<Product> | if_not_exists)(conn);
  if (!create_result) {
    throw std::runtime_error("Failed to create table");
  }

  // 3. Insert products
  auto insert_result = insert(products)(conn);
  if (!insert_result) {
    throw std::runtime_error("Failed to insert products");
  }

  // 4. Build and execute mathematical analysis query
  auto query = select_from<Product>(
    "product_id"_c,
    "name"_c,
    abs("price"_c) | as<"abs_price">,
    ceil("price"_c) | as<"ceil_price">,
    floor("price"_c) | as<"floor_price">,
    round("price"_c, 2) | as<"rounded_price">,
