 * Returns: bool indicating if child record was successfully deleted via cascade.
 */
bool cascade_delete_demo() {
  using namespace sqlgen::literals;

  // 1. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false; // Connection failed
  }
  auto conn = *conn_result;

  // 2. Create tables with proper constraints
