      "CREATE TABLE Parent (parent_id INTEGER PRIMARY KEY, name TEXT NOT NULL)"
  );
  if (!create_parent_result) {
    return false; // Parent table creation failed
  }

  auto create_child_result = conn.execute(
      "CREATE TABLE Child (child_id INTEGER PRIMARY KEY, parent_id INTEGER REFERENCES Parent(parent_id) ON DELETE CASCADE, note TEXT)"
  );
  if (!create_child_result) {
    return false; // Child table creation failed
