  // 3. Insert parent and child records
  auto insert_parent_result = conn.execute(
      "INSERT INTO Parent (parent_id, name) VALUES (1, 'Test Parent')"
  );
  if (!insert_parent_result) {
    return false; // Parent insertion failed
  }

  auto insert_child_result = conn.execute(
      "INSERT INTO Child (child_id, parent_id, note) VALUES (1, 1, 'Test Child Note')"
  );
  if (!insert_child_result) {
    return false; // Child insertion failed
