    auto query = sqlgen::select_from<Profile>(
        sqlgen::coalesce("nickname"_c, "Anonymous") | sqlgen::as<"display_name">
    ) | sqlgen::to<std::vector<NicknameResult>>;

    return query;
}

}  // namespace coalesce_function
